// buildOrgPolicy builds an OrgPolicy from a resolved resource.
func (b *Builder) buildOrgPolicy(ref string, res *resolver.ResolvedResource) {
	orgPolicy := &OrgPolicy{
		TFName: res.Name,
	}

	// Extract name
	if name := b.getAttrAsString(res, "name"); name != "" {
		orgPolicy.Name = name
	}

	// Extract type (defaults to SCP)
	if policyType := b.getAttrAsString(res, "type"); policyType != "" {
		orgPolicy.PolicyType = policyType
	} else {
		orgPolicy.PolicyType = "SERVICE_CONTROL_POLICY"
	}

	// Parse policy document (content attribute)
	if content := b.getAttrAsString(res, "content"); content != "" {
		doc, err := ParsePolicyDocument(content)
		if err == nil {
			orgPolicy.Policy = doc
			// Extract actions
			orgPolicy.AllowActions = doc.GetAllActions()
			orgPolicy.DenyActions = doc.GetDeniedActions()
		}
	}

	b.config.OrgPolicies = append(b.config.OrgPolicies, orgPolicy)
}

// handlePublicAccessBlock updates the corresponding bucket's HasBPA flag.
func (b *Builder) handlePublicAccessBlock(res *resolver.ResolvedResource) {
	// Find the bucket reference
	bucketRef := ""
	if bucket := b.getAttrAsString(res, "bucket"); bucket != "" {
		bucketRef = extractResourceRef(bucket)
	}
	if bucketRef == "" {
		for _, r := range res.References {
			if strings.HasPrefix(r, "aws_s3_bucket.") {
				bucketRef = r
				break
			}
		}
	}

	if bucketRef == "" {
		return
	}

	// Find and update the bucket
	bucketName := strings.TrimPrefix(bucketRef, "aws_s3_bucket.")
	for _, bucket := range b.config.Buckets {
		if bucket.TFName == bucketName {
			bucket.HasBPA = true
			break
		}
	}
}

// handleRolePolicyAttachment updates the corresponding role's HasRolePolicy flag.
func (b *Builder) handleRolePolicyAttachment(res *resolver.ResolvedResource) {
	// Find the role reference from attributes or references
	roleRef := ""
	if role := b.getAttrAsString(res, "role"); role != "" {
		roleRef = extractResourceRef(role)
	}
	if roleRef == "" {
		for _, r := range res.References {
			if strings.HasPrefix(r, "aws_iam_role.") {
				roleRef = r
				break
			}
		}
	}

	if roleRef == "" {
		return
	}

	// Find the policy reference from attributes or references
	policyRef := ""
	for _, r := range res.References {
		if strings.HasPrefix(r, "aws_iam_policy.") {
			policyRef = r
			break
		}
	}

	// Find and update the role
	roleName := strings.TrimPrefix(roleRef, "aws_iam_role.")
	for _, role := range b.config.Roles {
		if role.TFName == roleName {
			role.HasRolePolicy = true

			// Extract actions from the attached policy
			if policyRef != "" {
				policyName := strings.TrimPrefix(policyRef, "aws_iam_policy.")
				if p := b.config.GetPolicyByTFName(policyName); p != nil && p.Policy != nil {
					role.RolePolicyActions = append(role.RolePolicyActions, p.Policy.GetAllActions()...)
				}
			}
			break
		}
	}
}

// linkResources establishes relationships between resources.
func (b *Builder) linkResources() {
	// Link role policies to roles
	for _, rp := range b.config.RolePolicies {
		if rp.RoleRef == "" {
			continue
		}
		roleName := strings.TrimPrefix(rp.RoleRef, "aws_iam_role.")
		for _, role := range b.config.Roles {
			if role.TFName == roleName {
				role.HasRolePolicy = true
				if rp.Policy != nil {
					role.RolePolicyActions = append(role.RolePolicyActions, rp.Policy.GetAllActions()...)
				}
				break
			}
		}
	}

	// Link user policies to users
	for _, up := range b.config.UserPolicies {
		if up.UserRef == "" {
			continue
		}
		userName := strings.TrimPrefix(up.UserRef, "aws_iam_user.")
		for _, user := range b.config.Users {
			if user.TFName == userName {
				user.HasUserPolicy = true
				break
			}
		}
	}

	// Link boundaries to roles
	for _, role := range b.config.Roles {
		if role.BoundaryRef == "" {
			continue
		}
		policyName := strings.TrimPrefix(role.BoundaryRef, "aws_iam_policy.")
		if p := b.config.GetPolicyByTFName(policyName); p != nil && p.Policy != nil {
			role.BoundaryActions = p.Policy.GetAllActions()
		}
	}
}

// Helper methods

func (b *Builder) getAttrAsString(res *resolver.ResolvedResource, name string) string {
	if val, ok := res.Attributes[name]; ok {
		if s, ok := val.(string); ok {
			return s
		}
	}
	return ""
}

func (b *Builder) getAttrAsMap(res *resolver.ResolvedResource, name string) map[string]string {
	if val, ok := res.Attributes[name]; ok {
		if m, ok := val.(map[string]interface{}); ok {
			result := make(map[string]string)
			for k, v := range m {
				if s, ok := v.(string); ok {
					result[k] = s
				}
			}
			return result
		}
	}
	return nil
}

// extractResourceRef extracts a resource reference from various formats.
func extractResourceRef(s string) string {
	// Try Terraform reference format: aws_s3_bucket.name.attribute
	re := regexp.MustCompile(`(aws_[a-z0-9_]+)\.([a-z0-9_]+)`)
	matches := re.FindStringSubmatch(s)
	if len(matches) >= 3 {
		return matches[1] + "." + matches[2]
	}
	return ""
}

// BuildFromResources is a convenience function that creates a Builder and builds the Config.
func BuildFromResources(resources map[string]*resolver.ResolvedResource, graph *resolver.DependencyGraph) (*Config, error) {
	builder := NewBuilder(resources, graph)
	return builder.Build()
}

// Package ir defines the intermediate representation (IR) for AWS resources.
// This domain model is independent of Terraform and HCL parsing details.
package ir

// Config holds the complete parsed AWS configuration.
type Config struct {
	Buckets        []*S3Bucket
	BucketPolicies []*BucketPolicy
	Roles          []*IAMRole
	RolePolicies   []*RolePolicy
	Users          []*IAMUser
	UserPolicies   []*UserPolicy
	Policies       []*IAMPolicy
	OrgPolicies    []*OrgPolicy
}

// S3Bucket represents an aws_s3_bucket resource.
type S3Bucket struct {
	TFName string            // Terraform resource name
	Tags   map[string]string // Resource tags
	EnvTag string            // Environment tag value (extracted from tags)
	HasBPA bool              // Has aws_s3_bucket_public_access_block
}

// BucketPolicy represents an aws_s3_bucket_policy resource.
type BucketPolicy struct {
	TFName          string             // Terraform resource name
	BucketRef       string             // Reference to the bucket (e.g., "aws_s3_bucket.data")
	Policy          *IAMPolicyDocument // Parsed policy document
	DenyVpceID      string             // VPCE ID from explicit deny condition
	AllowPrincipals []string           // Principal ARNs/refs that are allowed
	AllowActions    []string           // Actions that are allowed
	HasABAC         bool               // Has PrincipalTag condition
}

// IAMRole represents an aws_iam_role resource.
type IAMRole struct {
	TFName             string   // Terraform resource name
	Name               string   // AWS role name
	EnvTag             string   // Environment tag value
	Tags               map[string]string
	HasRolePolicy      bool     // Has attached role policy
	RolePolicyActions  []string // Actions from attached policies
	HasBoundary        bool     // Has permissions boundary
	BoundaryRef        string   // Reference to boundary policy
	BoundaryActions    []string // Actions allowed by boundary
	HasSessionPolicy   bool     // AssumeRole with session policy
	AssumeRolePolicy   *IAMPolicyDocument
}

// RolePolicy represents an aws_iam_role_policy resource.
type RolePolicy struct {
	TFName  string             // Terraform resource name
	RoleRef string             // Reference to the role
	Policy  *IAMPolicyDocument // Parsed policy document
}

// IAMUser represents an aws_iam_user resource.
type IAMUser struct {
	TFName        string
	Name          string
	EnvTag        string
	Tags          map[string]string
	HasUserPolicy bool
}

// UserPolicy represents an aws_iam_user_policy resource.
type UserPolicy struct {
	TFName  string
	UserRef string
	Policy  *IAMPolicyDocument
}

// IAMPolicy represents an aws_iam_policy resource (standalone policy).
type IAMPolicy struct {
	TFName string
	Name   string
	ARN    string
	Policy *IAMPolicyDocument
}

// OrgPolicy represents an aws_organizations_policy resource.
type OrgPolicy struct {
	TFName       string             // Terraform resource name
	Name         string             // Policy name
	PolicyType   string             // "SERVICE_CONTROL_POLICY" (SCP) or "RESOURCE_CONTROL_POLICY" (RCP)
	Policy       *IAMPolicyDocument // Parsed policy document
	AllowActions []string           // Actions explicitly allowed
	DenyActions  []string           // Actions explicitly denied
}

// IAMPolicyDocument represents a parsed IAM policy document.
type IAMPolicyDocument struct {
	Version    string       `json:"Version"`
	ID         string       `json:"Id,omitempty"`
	Statements []*Statement `json:"Statement"`
}

// Statement represents a single statement in an IAM policy.
type Statement struct {
	SID        string      `json:"Sid,omitempty"`
	Effect     string      `json:"Effect"`
	Actions    []string    // Normalized from Action/NotAction
	NotActions []string    // NotAction field
	Resources  []string    // Normalized from Resource/NotResource
	Principals []Principal // Normalized from Principal
	Conditions []Condition // Parsed conditions
}

// Principal represents a principal in an IAM policy statement.
type Principal struct {
	Type  string // "AWS", "Service", "Federated", "*"
	Value string // ARN, service name, or "*"
}

// Condition represents a condition in an IAM policy statement.
type Condition struct {
	Operator string // "StringEquals", "StringNotEquals", "ArnEquals", etc.
	Key      string // "aws:sourceVpce", "aws:PrincipalTag/environment", etc.
	Values   []string
}

// Helper methods

// IsSCP returns true if this is a Service Control Policy.
func (op *OrgPolicy) IsSCP() bool {
	return op.PolicyType == "SERVICE_CONTROL_POLICY" || op.PolicyType == "SCP"
}

// IsRCP returns true if this is a Resource Control Policy.
func (op *OrgPolicy) IsRCP() bool {
	return op.PolicyType == "RESOURCE_CONTROL_POLICY" || op.PolicyType == "RCP"
}

// GetBucketByTFName finds a bucket by its Terraform name.
func (c *Config) GetBucketByTFName(name string) *S3Bucket {
	for _, b := range c.Buckets {
		if b.TFName == name {
			return b
		}
	}
	return nil
}

// GetRoleByTFName finds a role by its Terraform name.
func (c *Config) GetRoleByTFName(name string) *IAMRole {
	for _, r := range c.Roles {
		if r.TFName == name {
			return r
		}
	}
	return nil
}

// GetUserByTFName finds a user by its Terraform name.
func (c *Config) GetUserByTFName(name string) *IAMUser {
	for _, u := range c.Users {
		if u.TFName == name {
			return u
		}
	}
	return nil
}

// GetPolicyByTFName finds a standalone IAM policy by its Terraform name.
func (c *Config) GetPolicyByTFName(name string) *IAMPolicy {
	for _, p := range c.Policies {
		if p.TFName == name {
			return p
		}
	}
	return nil
}

// SCPs returns all Service Control Policies.
func (c *Config) SCPs() []*OrgPolicy {
	var scps []*OrgPolicy
	for _, op := range c.OrgPolicies {
		if op.IsSCP() {
			scps = append(scps, op)
		}
	}
	return scps
}

// RCPs returns all Resource Control Policies.
func (c *Config) RCPs() []*OrgPolicy {
	var rcps []*OrgPolicy
	for _, op := range c.OrgPolicies {
		if op.IsRCP() {
			rcps = append(rcps, op)
		}
	}
	return rcps
}

